namespace Payments;

public sealed class PaymentGateway
{
    public Task<ChargeResult> ChargeAsync(string cardToken, decimal amount) => throw new NotImplementedException();
    public Task<RefundResult> RefundAsync(string chargeId) => throw new NotImplementedException();
}

public record ChargeResult(string ChargeId, bool Success);
public record RefundResult(string RefundId, bool Success);

using Payments;

namespace PaymentGateway.Tests;

[TestClass]
public sealed class PaymentGatewayTests
{
    private readonly Payments.PaymentGateway _gateway;

    public PaymentGatewayTests()
    {
        _gateway = new Payments.PaymentGateway();
    }

    // ── ChargeAsync ─────────────────────────────────────────────

    [TestMethod]
    public async Task ChargeAsync_ValidTokenAndAmount_ReturnsSuccessResult()
    {
        var result = await _gateway.ChargeAsync("tok_valid_visa", 49.99m);

        Assert.IsNotNull(result);
        Assert.IsTrue(result.Success);
        Assert.IsNotNull(result.ChargeId);
    }

    [TestMethod]
    public async Task ChargeAsync_ValidCharge_ReturnsNonEmptyChargeId()
    {
        var result = await _gateway.ChargeAsync("tok_valid_visa", 100m);

        Assert.IsTrue(result.Success);
        Assert.AreNotEqual(string.Empty, result.ChargeId);
    }

    [TestMethod]
    [DataRow(null)]
    [DataRow("")]
    [DataRow("   ")]
    public async Task ChargeAsync_NullOrEmptyToken_ThrowsArgumentException(string? cardToken)
    {
        await Assert.ThrowsExactlyAsync<ArgumentException>(
            async () => await _gateway.ChargeAsync(cardToken!, 10m));
    }

    [TestMethod]
    [DataRow(0)]
    [DataRow(-1)]
    [DataRow(-100.50)]
    public async Task ChargeAsync_ZeroOrNegativeAmount_ThrowsArgumentOutOfRangeException(double amount)
    {
        await Assert.ThrowsExactlyAsync<ArgumentOutOfRangeException>(
            async () => await _gateway.ChargeAsync("tok_valid", (decimal)amount));
    }

    [TestMethod]
    public async Task ChargeAsync_DeclinedCard_ReturnsFailureResult()
    {
        var result = await _gateway.ChargeAsync("tok_declined", 50m);

        Assert.IsNotNull(result);
        Assert.IsFalse(result.Success);
    }

    [TestMethod]
    [DataRow(0.01)]
    [DataRow(999_999.99)]
    public async Task ChargeAsync_BoundaryAmounts_ReturnsSuccessResult(double amount)
    {
        var result = await _gateway.ChargeAsync("tok_valid_visa", (decimal)amount);

        Assert.IsTrue(result.Success);
    }

    [TestMethod]
    public async Task ChargeAsync_TwoCharges_ReturnDistinctChargeIds()
    {
        var result1 = await _gateway.ChargeAsync("tok_valid_visa", 10m);
        var result2 = await _gateway.ChargeAsync("tok_valid_visa", 20m);

        Assert.AreNotEqual(result1.ChargeId, result2.ChargeId);
    }

    // ── RefundAsync ─────────────────────────────────────────────

    [TestMethod]
    public async Task RefundAsync_ValidChargeId_ReturnsSuccessResult()
    {
        // Arrange — create a charge first
        var charge = await _gateway.ChargeAsync("tok_valid_visa", 75m);

        // Act
        var refund = await _gateway.RefundAsync(charge.ChargeId);

        // Assert
        Assert.IsNotNull(refund);
        Assert.IsTrue(refund.Success);
        Assert.IsNotNull(refund.RefundId);
    }

    [TestMethod]
    public async Task RefundAsync_ValidRefund_ReturnsNonEmptyRefundId()
    {
        var charge = await _gateway.ChargeAsync("tok_valid_visa", 50m);

        var refund = await _gateway.RefundAsync(charge.ChargeId);

        Assert.AreNotEqual(string.Empty, refund.RefundId);
    }

    [TestMethod]
    [DataRow(null)]
    [DataRow("")]
    [DataRow("   ")]
    public async Task RefundAsync_NullOrEmptyChargeId_ThrowsArgumentException(string? chargeId)
    {
        await Assert.ThrowsExactlyAsync<ArgumentException>(
            async () => await _gateway.RefundAsync(chargeId!));
    }

    [TestMethod]
    public async Task RefundAsync_NonExistentChargeId_ThrowsInvalidOperationException()
    {
        await Assert.ThrowsExactlyAsync<InvalidOperationException>(
            async () => await _gateway.RefundAsync("chg_nonexistent"));
    }

    [TestMethod]
    public async Task RefundAsync_AlreadyRefundedCharge_ThrowsInvalidOperationException()
    {
        var charge = await _gateway.ChargeAsync("tok_valid_visa", 25m);
        await _gateway.RefundAsync(charge.ChargeId);

        await Assert.ThrowsExactlyAsync<InvalidOperationException>(
            async () => await _gateway.RefundAsync(charge.ChargeId));
    }

    // ── ChargeResult / RefundResult records ─────────────────────

    [TestMethod]
    public void ChargeResult_EqualValues_AreEqual()
    {
        var a = new ChargeResult("chg_1", true);
        var b = new ChargeResult("chg_1", true);

        Assert.AreEqual(a, b);
    }

    [TestMethod]
    public void RefundResult_DifferentIds_AreNotEqual()
    {
        var a = new RefundResult("ref_1", true);
        var b = new RefundResult("ref_2", true);

        Assert.AreNotEqual(a, b);
    }
}

